import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { listenAuction, startAuction, closeAuction, listenPlayers, resetAllWins } from '../firebase/services';
import toast from 'react-hot-toast';

export default function AdminDashboard() {
  const { logout } = useAuth(); // ✅ Get logout from context
  const [auction, setAuction] = useState(null);
  const [players, setPlayers] = useState([]);
  const [settings, setSettings] = useState({ monthlyAmount: 5000, totalPlayers: 10 });

  useEffect(() => {
    const unsubs = [
      listenAuction(setAuction),
      listenPlayers(setPlayers)
    ];
    return () => unsubs.forEach(u => u());
  }, []);

  const handleStart = async () => {
    try {
      await startAuction(settings);
      toast.success("Auction started! Players can now bid.");
    } catch (err) { toast.error(err.message); }
  };

  const handleClose = async () => {
    if (!window.confirm("Close auction and announce winner?")) return;
    try {
      await closeAuction(auction);
      toast.success("Auction closed successfully!");
    } catch (err) { toast.error(err.message); }
  };

  const handleReset = async () => {
    if (!window.confirm("This will reset all winners for a new 10-month cycle. Continue?")) return;
    try {
      await resetAllWins();
      toast.success("All players reset to pending!");
    } catch (err) { toast.error(err.message); }
  };

  return (
    <div className="page-wide">
      {/* --- Unified Navbar --- */}
      <div className="navbar">
        <div>
          <div className="navbar-brand">👑 Admin Panel</div>
          <div className="navbar-sub">Manage your 10-member group</div>
        </div>
        <div style={{ display: 'flex', gap: '10px' }}>
          <button className="btn btn-ghost btn-sm" onClick={() => window.location.reload()}>Refresh</button>
          <button className="btn btn-danger btn-sm" onClick={logout}>Logout</button>
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1.5fr', gap: '20px' }}>

        {/* --- Column 1: Controls --- */}
        <div>
          <div className="card">
            <h3 className="card-title">Group Settings</h3>
            <div className="form-group" style={{ marginTop: '15px' }}>
              <label className="form-label">Monthly Contribution</label>
              <input type="number" className="form-input" value={settings.monthlyAmount} 
                onChange={e => setSettings({...settings, monthlyAmount: Number(e.target.value)})} />
            </div>
            <div className="form-group">
              <label className="form-label">Total Players</label>
              <input type="number" className="form-input" value={settings.totalPlayers} 
                onChange={e => setSettings({...settings, totalPlayers: Number(e.target.value)})} />
            </div>
          </div>

          <div className="card" style={{ textAlign: 'center' }}>
            <h3 className="card-title" style={{ marginBottom: '15px' }}>Auction Control</h3>
            {auction?.active ? (
              <>
                <div className="badge badge-green" style={{ marginBottom: '10px' }}>LIVE NOW</div>
                <div className="bid-amount" style={{ fontSize: '2rem', marginBottom: '15px' }}>₹{auction.currentBid?.toLocaleString('en-IN')}</div>
                <button className="btn btn-danger btn-full" onClick={handleClose}>End Auction</button>
              </>
            ) : (
              <button className="btn btn-primary btn-full" onClick={handleStart}>Start New Auction</button>
            )}
            <div className="divider"></div>
            <button className="btn btn-ghost btn-sm btn-full" onClick={handleReset}>Reset All Wins</button>
          </div>
        </div>

        {/* --- Column 2: Player Status --- */}
        <div className="card">
          <div className="card-header">
            <h3 className="card-title">Member Status</h3>
            <span className="badge badge-gold">{players.length} Total</span>
          </div>
          <div className="players-grid" style={{ gridTemplateColumns: '1fr' }}>
            {players.map(player => (
              <div key={player.id} className={`player-chip ${player.hasWon ? 'won' : ''}`}>
                <div className="player-avatar">{player.hasWon ? '🏆' : player.name?.[0]}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 600 }}>{player.name}</div>
                  <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{player.email}</div>
                </div>
                {player.hasWon ? (
                  <span className="badge badge-gold">Won: {player.wonMonth}</span>
                ) : (
                  <span className="badge badge-muted">Pending</span>
                )}
              </div>
            ))}
          </div>
        </div>

      </div>
    </div>
  );
}
